methods: {
  getImageUrl(url) {
    if (!url) return 'https://via.placeholder.com/600x400';
    
    // 이미 전체 URL인 경우 그대로 반환
    if (url.startsWith('http://') || url.startsWith('https://')) {
      return url;
    }
    
    // 상대 경로인 경우 baseUrl 추가
    return `${this.baseUrl}${url}`;
  }
}

